import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import java.net.URI;
import java.util.List;

@RestController
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/webhooks")
    public String handleWebhook(@RequestBody List<Webhook> webhooks) {
        for (Webhook webhook : webhooks) {
            try {
                URI uri = new URI(webhook.getUrl());
                HttpHeaders headers = new HttpHeaders();
                HttpEntity<String> entity = new HttpEntity<>(headers);
                ResponseEntity<String> response = restTemplate.exchange(uri, HttpMethod.GET, entity, String.class);

                if (response.getStatusCode().is2xxSuccessful()) {
                    return "Webhook received and processed successfully";
                } else {
                    return "Error processing webhook: " + response.getBody();
                }
            } catch (Exception e) {
                return "Error processing webhook: " + e.getMessage();
            }
        }

        return "No webhooks to process";
    }
}

class Webhook {
    private String url;

    public String getUrl() {
        return url;
    }

    public void setUrl(String url) {
        this.url = url;
    }
}